import React from "react";
import axios from "axios";

class Data extends React.Component {
  constructor(props) {
    super(props);
    this.ip = "";
    this.data = "";
    this.loggedIn = false;
  }

  getClockState() {
    if (this.ip !== "") {
      console.log("try");
      axios
        .get("http://" + this.state.ip, { timeout: 1000 })
        .then((result) => {
          this.setState({
            data: result.data,
            isLoading: false,
          });
          if (this.state.data.NAME === "WallClock") {
            this.props.history.push({
              pathname: "/home",
              state: [{ ip: this.state.ip, data: this.state.data }],
            });
          }
        })
        .catch((error) =>
          this.setState({
            isLoading: false,
            lastLoginFailed: true,
          })
        );
    } else {
      this.setState({ isLoading: false });
      this.setState({ lastLoginFailed: true });
    }
  }
}

export default Data;
